            var result = controller.Index(null!, null!, null!, null) as ViewResult;

            Assert.NotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.NotNull(model);
            var lastNames = model.Select(s => s.LastName).ToList();
            var sorted = lastNames.OrderBy(n => n).ToList();
            Assert.Equal(sorted, lastNames);
        }

