#nullable enable

using System;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Text;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly List<string> _tempDirs = new();

        private (CoursesController controller, SchoolContext context, Mock<IWebHostEnvironment> envMock) CreateController(bool seed = true)
        {
            var context = TestHelpers.CreateContext();
            if (seed)
            {
                TestHelpers.SeedData(context);
            }

            var envMock = new Mock<IWebHostEnvironment>();
            var webRoot = Path.Combine(Path.GetTempPath(), "wwwroot_test_" + Guid.NewGuid());
            var contentRoot = Path.Combine(Path.GetTempPath(), "content_test_" + Guid.NewGuid());
            envMock.Setup(e => e.WebRootPath).Returns(webRoot);
            envMock.Setup(e => e.ContentRootPath).Returns(contentRoot);
            _tempDirs.Add(webRoot);
            _tempDirs.Add(contentRoot);

            var loggerMock = new Mock<ILogger<CoursesController>>();

            var controller = new CoursesController(context, envMock.Object, loggerMock.Object);
            return (controller, context, envMock);
        }

        private static Mock<IFormFile> CreateMockFile(string fileName = "test.jpg", long? overrideLength = null)
        {
            var fileMock = new Mock<IFormFile>();
            var content = "fake image content";
            var ms = new MemoryStream(Encoding.UTF8.GetBytes(content));
            fileMock.Setup(f => f.FileName).Returns(fileName);
            fileMock.Setup(f => f.Length).Returns(overrideLength ?? ms.Length);
            fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>())).Callback<Stream>(s =>
            {
                ms.Position = 0;
                ms.CopyTo(s);
            });
            fileMock.Setup(f => f.OpenReadStream()).Returns(() =>
            {
                ms.Position = 0;
                return ms;
            });
            return fileMock;
        }

        public void Dispose()
        {
            foreach (var dir in _tempDirs)
            {
                try
                {
                    if (Directory.Exists(dir))
                    {
                        Directory.Delete(dir, recursive: true);
                    }
                }
                catch { }
            }
        }

        // ===== Index =====

        [Fact]
        public void Index_ReturnsViewResult_WithListOfCourses()
        {
            var (controller, context, _) = CreateController();

            var result = controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<Course>>(viewResult.Model);
            Assert.True(model.Count > 0);
            Assert.All(model, c => Assert.NotNull(c.Department));
        }

        // ===== Details =====

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var (controller, _, _) = CreateController();

            var result = controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsCourseWithDepartment()
        {
            var (controller, context, _) = CreateController();
            var course = context.Courses.First();

            var result = controller.Details(course.CourseID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal(course.CourseID, model.CourseID);
            Assert.NotNull(model.Department);
        }

        // ===== Create GET =====

        [Fact]
        public void Create_Get_ReturnsViewResult_WithNewCourse()
        {
            var (controller, _, _) = CreateController();

            var result = controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal(0, model.CourseID);
        }

        [Fact]
        public void Create_Get_SetsViewBagDepartmentID()
        {
            var (controller, _, _) = CreateController();

            var result = controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.NotNull(viewResult.ViewData["DepartmentID"]);
        }

        // ===== Create POST =====

        [Fact]
        public void Create_Post_ValidCourseWithoutImage_SavesAndRedirects()
        {
            var (controller, context, _) = CreateController();
            var dept = context.Departments.First();
            var course = new Course
            {
                CourseID = 9999,
                Title = "New Test Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var result = controller.Create(course, null!);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.NotNull(context.Courses.Find(9999));
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            var (controller, context, _) = CreateController();
            controller.ModelState.AddModelError("Title", "Required");
            var course = new Course
            {
                CourseID = 9998,
                DepartmentID = context.Departments.First().DepartmentID
            };

            var result = controller.Create(course, null!);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Course>(viewResult.Model);
            Assert.NotNull(viewResult.ViewData["DepartmentID"]);
        }

        [Theory]
        [InlineData("test.txt")]
        [InlineData("document.pdf")]
        [InlineData("script.exe")]
        public void Create_Post_InvalidFileExtension_ReturnsViewWithError(string fileName)
        {
            var (controller, context, _) = CreateController();
            var dept = context.Departments.First();
            var course = new Course
            {
                CourseID = 9997,
                Title = "File Test",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            var fileMock = CreateMockFile(fileName);

            var result = controller.Create(course, fileMock.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_FileExceeds5MB_ReturnsViewWithError()
        {
            var (controller, context, _) = CreateController();
            var dept = context.Departments.First();
            var course = new Course
            {
                CourseID = 9996,
                Title = "Large File Test",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            var fileMock = CreateMockFile("large.jpg", overrideLength: 6 * 1024 * 1024);

            var result = controller.Create(course, fileMock.Object);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.True(controller.ModelState.ContainsKey("teachingMaterialImage"));
            var error = controller.ModelState["teachingMaterialImage"]!.Errors.First().ErrorMessage;
            Assert.Contains("5MB", error);
        }

        [Fact]
        public void Create_Post_ValidImage_SavesFileAndCourse()
        {
            var (controller, context, envMock) = CreateController();
            var dept = context.Departments.First();
            var course = new Course
            {
                CourseID = 9995,
                Title = "Image Upload Test",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            var fileMock = CreateMockFile("test.png");

            var result = controller.Create(course, fileMock.Object);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);

            var savedCourse = context.Courses.Find(9995);
            Assert.NotNull(savedCourse);
            Assert.NotNull(savedCourse!.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", savedCourse.TeachingMaterialImagePath);

            // Verify file was physically written
            var webRoot = envMock.Object.WebRootPath;
            var uploadsDir = Path.Combine(webRoot, "Uploads", "TeachingMaterials");
            Assert.True(Directory.Exists(uploadsDir));
            Assert.NotEmpty(Directory.GetFiles(uploadsDir));
        }

        // ===== Edit GET =====

        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var (controller, _, _) = CreateController();

            var result = controller.Edit(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_NotFound_ReturnsNotFound()
        {
            var (controller, _, _) = CreateController();

            var result = controller.Edit(99999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsCourseWithViewBag()
        {
            var (controller, context, _) = CreateController();
            var course = context.Courses.First();

            var result = controller.Edit(course.CourseID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal(course.CourseID, model.CourseID);
            Assert.NotNull(viewResult.ViewData["DepartmentID"]);
        }

        // ===== Edit POST =====

        [Fact]
        public void Edit_Post_ValidCourseWithoutImage_UpdatesAndRedirects()
        {
            var (controller, context, _) = CreateController();
            var existing = context.Courses.First();
            // Detach the tracked entity so Edit's EntityState.Modified doesn't conflict
            context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updatedCourse = new Course
            {
                CourseID = existing.CourseID,
                Title = "Updated Title",
                Credits = existing.Credits,
                DepartmentID = existing.DepartmentID
            };

            var result = controller.Edit(updatedCourse, null!);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);

            var reloaded = context.Courses.Find(existing.CourseID);
            Assert.Equal("Updated Title", reloaded!.Title);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            var (controller, context, _) = CreateController();
            controller.ModelState.AddModelError("Title", "Required");
            var course = context.Courses.First();

            var result = controller.Edit(course, null!);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.NotNull(viewResult.ViewData["DepartmentID"]);
        }

        [Fact]
        public void Edit_Post_ValidImageUpload_UpdatesCourse()
        {
            var (controller, context, envMock) = CreateController();
            var existing = context.Courses.First();
            context.Entry(existing).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var editedCourse = new Course
            {
                CourseID = existing.CourseID,
                Title = existing.Title,
                Credits = existing.Credits,
                DepartmentID = existing.DepartmentID
            };
            var fileMock = CreateMockFile("updated.jpg");

            var result = controller.Edit(editedCourse, fileMock.Object);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);

            var reloaded = context.Courses.Find(existing.CourseID);
            Assert.NotNull(reloaded!.TeachingMaterialImagePath);
            Assert.Contains("/Uploads/TeachingMaterials/", reloaded.TeachingMaterialImagePath);

            var webRoot = envMock.Object.WebRootPath;
            var uploadsDir = Path.Combine(webRoot, "Uploads", "TeachingMaterials");
            Assert.True(Directory.Exists(uploadsDir));
            Assert.NotEmpty(Directory.GetFiles(uploadsDir));
        }

        // ===== Delete GET =====

        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var (controller, _, _) = CreateController();

            var result = controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsCourseWithDepartment()
        {
            var (controller, context, _) = CreateController();
            var course = context.Courses.First();

            var result = controller.Delete(course.CourseID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Course>(viewResult.Model);
            Assert.Equal(course.CourseID, model.CourseID);
            Assert.NotNull(model.Department);
        }

        // ===== DeleteConfirmed =====

        [Fact]
        public void DeleteConfirmed_DeletesCourseAndRedirects()
        {
            var (controller, context, _) = CreateController();
            var course = context.Courses.First();
            var courseId = course.CourseID;

            var result = controller.DeleteConfirmed(courseId);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Null(context.Courses.Find(courseId));
        }
    }
}

