using System;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests.Services
{
    [Collection("NotificationService")]
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            DrainQueue();
        }

        public void Dispose()
        {
            DrainQueue();
            _service.Dispose();
        }

        private void DrainQueue()
        {
            while (_service.ReceiveNotification() != null) { }
        }

        [Fact]
        public void SendNotification_EnqueuesNotification_ReceiveDequeuesIt()
        {
            // Arrange & Act
            _service.SendNotification("Student", "1", "Carson Alexander", EntityOperation.CREATE, "admin");
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.Equal("admin", notification.CreatedBy);
            Assert.False(notification.IsRead);
        }

        [Fact]
        public void SendNotification_WithDisplayName_GeneratesCorrectMessage()
        {
            // Arrange & Act
            _service.SendNotification("Course", "1050", "Chemistry", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.NotNull(notification);
            Assert.Equal("New Course 'Chemistry' has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutDisplayName_GeneratesIdBasedMessage()
        {
            // Arrange & Act
            _service.SendNotification("Student", "5", EntityOperation.UPDATE, "admin");
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.NotNull(notification);
            Assert.Equal("Student (ID: 5) has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteOperation_GeneratesDeleteMessage()
        {
            // Arrange & Act
            _service.SendNotification("Department", "3", "Engineering", EntityOperation.DELETE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.NotNull(notification);
            Assert.Equal("Department 'Engineering' has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteWithoutDisplayName_GeneratesDeleteMessage()
        {
            // Arrange & Act
            _service.SendNotification("Course", "4022", EntityOperation.DELETE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.NotNull(notification);
            Assert.Equal("Course (ID: 4022) has been deleted", notification.Message);
        }

        [Fact]
        public void ReceiveNotification_WhenQueueEmpty_ReturnsNull()
        {
            // Act
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.Null(notification);
        }

        [Fact]
        public void SendAndReceive_MultipleSends_ReturnsFifoOrder()
        {
            // Arrange
            _service.SendNotification("Course", "1", "First", EntityOperation.CREATE);
            _service.SendNotification("Course", "2", "Second", EntityOperation.UPDATE);
            _service.SendNotification("Course", "3", "Third", EntityOperation.DELETE);

            // Act & Assert
            var first = _service.ReceiveNotification();
            Assert.NotNull(first);
            Assert.Equal("1", first.EntityId);
            Assert.Equal("New Course 'First' has been created", first.Message);

            var second = _service.ReceiveNotification();
            Assert.NotNull(second);
            Assert.Equal("2", second.EntityId);
            Assert.Equal("Course 'Second' has been updated", second.Message);

            var third = _service.ReceiveNotification();
            Assert.NotNull(third);
            Assert.Equal("3", third.EntityId);
            Assert.Equal("Course 'Third' has been deleted", third.Message);

            Assert.Null(_service.ReceiveNotification());
        }

        [Fact]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            // Arrange & Act
            _service.SendNotification("Student", "10", "Carson Alexander", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.NotNull(notification);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_OverloadWithoutDisplayName_CallsThrough()
        {
            // Arrange & Act
            _service.SendNotification("Instructor", "7", EntityOperation.UPDATE, "testuser");
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.NotNull(notification);
            Assert.Equal("Instructor", notification.EntityType);
            Assert.Equal("7", notification.EntityId);
            Assert.Equal("UPDATE", notification.Operation);
            Assert.Equal("testuser", notification.CreatedBy);
            Assert.Equal("Instructor (ID: 7) has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            // Arrange
            var before = DateTime.Now;

            // Act
            _service.SendNotification("Course", "1050", "Chemistry", EntityOperation.CREATE);
            var after = DateTime.Now;
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.NotNull(notification);
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            // Arrange
            var service = new NotificationService();

            // Act & Assert
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            // Act & Assert
            var exception = Record.Exception(() => _service.MarkAsRead(42));
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_UpdateWithDisplayName_GeneratesUpdateMessage()
        {
            // Arrange & Act
            _service.SendNotification("Student", "10", "Carson Alexander", EntityOperation.UPDATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.NotNull(notification);
            Assert.Equal("Student 'Carson Alexander' has been updated", notification.Message);
        }
    }
}

