using System.Collections.Generic;
using System.Linq;
using Xunit;

namespace ContosoUniversity.Tests.Models
{
    public class PaginatedListTests
    {
        [Fact]
        public void Constructor_WithValidArgs_SetsPageIndexAndTotalPages()
        {
            // Arrange
            var items = new List<string> { "a", "b", "c" };

            // Act
            var list = new PaginatedList<string>(items, 10, 2, 5);

            // Assert
            Assert.Equal(2, list.PageIndex);
            Assert.Equal(2, list.TotalPages);
            Assert.Equal(3, list.Count);
            Assert.Contains("a", list);
            Assert.Contains("b", list);
            Assert.Contains("c", list);
        }

        [Theory]
        [InlineData(11, 5, 3)]
        [InlineData(10, 5, 2)]
        [InlineData(1, 5, 1)]
        [InlineData(0, 5, 0)]
        [InlineData(6, 3, 2)]
        [InlineData(7, 3, 3)]
        public void Constructor_TotalPages_RoundsUp(int totalCount, int pageSize, int expectedTotalPages)
        {
            // Arrange & Act
            var list = new PaginatedList<int>(new List<int>(), totalCount, 1, pageSize);

            // Assert
            Assert.Equal(expectedTotalPages, list.TotalPages);
        }

        [Fact]
        public void HasPreviousPage_OnPageOne_ReturnsFalse()
        {
            // Arrange & Act
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);

            // Assert
            Assert.False(list.HasPreviousPage);
        }

        [Theory]
        [InlineData(2)]
        [InlineData(3)]
        [InlineData(5)]
        public void HasPreviousPage_OnPageGreaterThanOne_ReturnsTrue(int pageIndex)
        {
            // Arrange & Act
            var list = new PaginatedList<int>(new List<int>(), 50, pageIndex, 5);

            // Assert
            Assert.True(list.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_NotOnLastPage_ReturnsTrue()
        {
            // Arrange & Act (page 1 of 2)
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 6, 1, 3);

            // Assert
            Assert.True(list.HasNextPage);
        }

        [Fact]
        public void HasNextPage_OnLastPage_ReturnsFalse()
        {
            // Arrange & Act (page 2 of 2)
            var list = new PaginatedList<int>(new List<int> { 4, 5, 6 }, 6, 2, 3);

            // Assert
            Assert.False(list.HasNextPage);
        }

        [Fact]
        public void Create_FirstPage_ReturnsCorrectItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 10).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 3);

            // Assert
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(4, result.TotalPages); // ceil(10/3) = 4
            Assert.Equal(3, result.Count);
            Assert.Equal(new List<int> { 1, 2, 3 }, result.ToList());
            Assert.True(result.HasNextPage);
            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 10).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 2, 3);

            // Assert
            Assert.Equal(2, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
            Assert.Equal(3, result.Count);
            Assert.Equal(new List<int> { 4, 5, 6 }, result.ToList());
            Assert.True(result.HasNextPage);
            Assert.True(result.HasPreviousPage);
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 10).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 4, 3);

            // Assert
            Assert.Equal(4, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
            Assert.Single(result);
            Assert.Equal(10, result[0]);
            Assert.False(result.HasNextPage);
            Assert.True(result.HasPreviousPage);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            // Arrange
            var source = new List<string>().AsQueryable();

            // Act
            var result = PaginatedList<string>.Create(source, 1, 5);

            // Assert
            Assert.Empty(result);
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(0, result.TotalPages);
            Assert.False(result.HasPreviousPage);
            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void Constructor_ItemsAreAddedToList()
        {
            // Arrange
            var items = new List<string> { "apple", "banana", "cherry" };

            // Act
            var list = new PaginatedList<string>(items, 3, 1, 3);

            // Assert
            Assert.Equal(3, list.Count);
            Assert.Equal("apple", list[0]);
            Assert.Equal("banana", list[1]);
            Assert.Equal("cherry", list[2]);
        }

        [Fact]
        public void HasNextPage_SinglePage_ReturnsFalse()
        {
            // Arrange & Act
            var list = new PaginatedList<int>(new List<int> { 1, 2 }, 2, 1, 5);

            // Assert
            Assert.False(list.HasNextPage);
            Assert.False(list.HasPreviousPage);
        }
    }
}

