using System;
using System.Collections.Generic;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests
{
    public static class TestHelpers
    {
        public static SchoolContext CreateContext()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
                .Options;

            return new SchoolContext(options);
        }

        public static SchoolContext CreateSeededContext()
        {
            var context = CreateContext();
            SeedData(context);
            return context;
        }

        public static void SeedData(SchoolContext context)
        {
            // Instructors
            var instructorKim = new Instructor
            {
                ID = 1,
                LastName = "Kim",
                FirstMidName = "Andrew",
                HireDate = new DateTime(2005, 3, 11),
                CourseAssignments = new List<CourseAssignment>()
            };

            var instructorHarui = new Instructor
            {
                ID = 2,
                LastName = "Harui",
                FirstMidName = "Roger",
                HireDate = new DateTime(2001, 7, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            var instructorKapoor = new Instructor
            {
                ID = 3,
                LastName = "Kapoor",
                FirstMidName = "Candace",
                HireDate = new DateTime(2003, 1, 15),
                CourseAssignments = new List<CourseAssignment>()
            };

            context.Instructors.AddRange(instructorKim, instructorHarui, instructorKapoor);

            // Students
            var studentAlexander = new Student
            {
                ID = 10,
                LastName = "Alexander",
                FirstMidName = "Carson",
                EnrollmentDate = new DateTime(2019, 9, 1),
                Enrollments = new List<Enrollment>()
            };

            var studentAlonso = new Student
            {
                ID = 11,
                LastName = "Alonso",
                FirstMidName = "Meredith",
                EnrollmentDate = new DateTime(2018, 9, 1),
                Enrollments = new List<Enrollment>()
            };

            var studentAnand = new Student
            {
                ID = 12,
                LastName = "Anand",
                FirstMidName = "Arturo",
                EnrollmentDate = new DateTime(2020, 9, 1),
                Enrollments = new List<Enrollment>()
            };

            context.Students.AddRange(studentAlexander, studentAlonso, studentAnand);

            // Departments
            var departmentEnglish = new Department
            {
                DepartmentID = 1,
                Name = "English",
                Budget = 350000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 1
            };

            var departmentMathematics = new Department
            {
                DepartmentID = 2,
                Name = "Mathematics",
                Budget = 100000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 2
            };

            var departmentEngineering = new Department
            {
                DepartmentID = 3,
                Name = "Engineering",
                Budget = 250000m,
                StartDate = new DateTime(2007, 9, 1),
                InstructorID = 3
            };

            context.Departments.AddRange(departmentEnglish, departmentMathematics, departmentEngineering);

            // Courses (CourseID is NOT auto-generated)
            var courseChemistry = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = 3
            };

            var courseMicroeconomics = new Course
            {
                CourseID = 4022,
                Title = "Microeconomics",
                Credits = 3,
                DepartmentID = 2
            };

            var courseComposition = new Course
            {
                CourseID = 2021,
                Title = "Composition",
                Credits = 3,
                DepartmentID = 1
            };

            context.Courses.AddRange(courseChemistry, courseMicroeconomics, courseComposition);

            // Save to establish keys before adding dependent entities
            context.SaveChanges();

            // Course Assignments
            context.CourseAssignments.AddRange(
                new CourseAssignment { CourseID = 1050, InstructorID = 3 },
                new CourseAssignment { CourseID = 4022, InstructorID = 2 },
                new CourseAssignment { CourseID = 2021, InstructorID = 1 }
            );

            // Office Assignments
            context.OfficeAssignments.AddRange(
                new OfficeAssignment { InstructorID = 1, Location = "Smith 17" },
                new OfficeAssignment { InstructorID = 2, Location = "Gowan 27" }
            );

            // Enrollments
            context.Enrollments.AddRange(
                new Enrollment { CourseID = 1050, StudentID = 10, Grade = Grade.A },
                new Enrollment { CourseID = 4022, StudentID = 11, Grade = Grade.C },
                new Enrollment { CourseID = 2021, StudentID = 12, Grade = null },
                new Enrollment { CourseID = 1050, StudentID = 11, Grade = Grade.B }
            );

            context.SaveChanges();
        }
    }
}

