using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class DepartmentsControllerTests
    {
        private static DepartmentsController CreateController(SchoolContext context)
        {
            var controller = new DepartmentsController(context);
            controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(), new SessionStateTempDataProvider());
            return controller;
        }

        private static (SchoolContext context, DepartmentsController controller) CreateSeeded()
        {
            var context = TestHelpers.CreateContext();
            TestHelpers.SeedData(context);
            return (context, CreateController(context));
        }

        #region Index

        [Fact]
        public void Index_ReturnsViewResult_WithListOfDepartments()
        {
            var (_, controller) = CreateSeeded();

            var result = controller.Index();

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsAssignableFrom<List<Department>>(viewResult.Model);
            Assert.Equal(3, model.Count);
        }

        [Fact]
        public void Index_IncludesAdministratorNavigation()
        {
            var (_, controller) = CreateSeeded();

            var result = controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Department>>(result!.Model);
            Assert.Contains(model, d => d.Administrator != null);
        }

        #endregion

        #region Details

        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var (_, controller) = CreateSeeded();

            var result = controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_NonExistentId_ReturnsNotFound()
        {
            var (_, controller) = CreateSeeded();

            var result = controller.Details(99999);

            Assert.IsType<NotFoundResult>(result);
        }

        [Fact]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            var (context, controller) = CreateSeeded();
