            var result = controller.Details(dept.DepartmentID);

            var viewResult = Assert.IsType<ViewResult>(result);
            var model = Assert.IsType<Department>(viewResult.Model);
            Assert.Equal(dept.DepartmentID, model.DepartmentID);
            Assert.Equal(dept.Name, model.Name);
        }

        #endregion

        #region Create GET

        [Fact]
        public void Create_Get_ReturnsViewResult()
        {
            var (_, controller) = CreateSeeded();

            var result = controller.Create();

            Assert.IsType<ViewResult>(result);
        }

        [Fact]
        public void Create_Get_SetsViewBagInstructorID()
        {
            var (_, controller) = CreateSeeded();

            var result = controller.Create();

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.NotNull(viewResult.ViewData["InstructorID"]);
            Assert.IsType<SelectList>(viewResult.ViewData["InstructorID"]);
        }

        #endregion

        #region Create POST

        [Fact]
        public void Create_Post_ValidDepartment_SavesAndRedirects()
        {
            var (context, controller) = CreateSeeded();
            var department = new Department
            {
                Name = "New Department",
                Budget = 100000m,
                StartDate = new DateTime(2023, 9, 1),
                InstructorID = 1
            };

            var result = controller.Create(department);

            var redirectResult = Assert.IsType<RedirectToActionResult>(result);
            Assert.Equal("Index", redirectResult.ActionName);
            Assert.Contains(context.Departments, d => d.Name == "New Department");
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsViewWithDepartment()
        {
            var (_, controller) = CreateSeeded();
            controller.ModelState.AddModelError("Name", "Required");
            var department = new Department
            {
                Budget = 100000m,
                StartDate = new DateTime(2023, 9, 1)
            };

            var result = controller.Create(department);

            var viewResult = Assert.IsType<ViewResult>(result);
            Assert.IsType<Department>(viewResult.Model);
            Assert.NotNull(viewResult.ViewData["InstructorID"]);
