using System;
using System.Collections.Generic;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Mvc;
using Xunit;

namespace ContosoUniversity.Tests.Controllers
{
    public class NotificationsControllerTests
    {
        /// <summary>
        /// Drains the static NotificationService queue to ensure test isolation.
        /// </summary>
        private static void DrainNotificationQueue()
        {
            using var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }
        }

        private static NotificationsController CreateController()
        {
            var context = TestHelpers.CreateContext();
            return new NotificationsController(context);
        }

        #region GetNotifications

        [Fact]
        public void GetNotifications_NoNotifications_ReturnsSuccessWithEmptyList()
        {
            DrainNotificationQueue();
            var controller = CreateController();

            var result = controller.GetNotifications();

            var jsonResult = Assert.IsType<JsonResult>(result);
            Assert.NotNull(jsonResult.Value);

            var value = jsonResult.Value!;
            var successProp = value.GetType().GetProperty("success");
            var countProp = value.GetType().GetProperty("count");
            var notificationsProp = value.GetType().GetProperty("notifications");

            Assert.True((bool)successProp!.GetValue(value)!);
            Assert.Equal(0, (int)countProp!.GetValue(value)!);

            var notifications = notificationsProp!.GetValue(value) as List<Notification>;
            Assert.NotNull(notifications);
            Assert.Empty(notifications!);
        }

        [Fact]
        public void GetNotifications_WithNotifications_ReturnsEnqueuedNotifications()
        {
            DrainNotificationQueue();
            var controller = CreateController();

            // Enqueue notifications via the shared static queue
            using var service = new NotificationService();
            service.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");
            service.SendNotification("Course", "2", EntityOperation.UPDATE, "TestUser");

            var result = controller.GetNotifications();

            var jsonResult = Assert.IsType<JsonResult>(result);
            Assert.NotNull(jsonResult.Value);

            var value = jsonResult.Value!;
            var successProp = value.GetType().GetProperty("success");
            var countProp = value.GetType().GetProperty("count");
            var notificationsProp = value.GetType().GetProperty("notifications");

            Assert.True((bool)successProp!.GetValue(value)!);
            Assert.Equal(2, (int)countProp!.GetValue(value)!);

            var notifications = notificationsProp!.GetValue(value) as List<Notification>;
            Assert.NotNull(notifications);
            Assert.Equal(2, notifications!.Count);
        }

        [Fact]
        public void GetNotifications_LimitsTo10Results()
        {
            DrainNotificationQueue();
            var controller = CreateController();

            using var service = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE, "TestUser");
            }

            var result = controller.GetNotifications();

            var jsonResult = Assert.IsType<JsonResult>(result);
            Assert.NotNull(jsonResult.Value);

            var value = jsonResult.Value!;
            var countProp = value.GetType().GetProperty("count");
            var notificationsProp = value.GetType().GetProperty("notifications");

            Assert.Equal(10, (int)countProp!.GetValue(value)!);

            var notifications = notificationsProp!.GetValue(value) as List<Notification>;
            Assert.NotNull(notifications);
            Assert.Equal(10, notifications!.Count);
        }

        #endregion

        #region MarkAsRead

        [Fact]
        public void MarkAsRead_ReturnsSuccess()
        {
            var controller = CreateController();

            var result = controller.MarkAsRead(1);

            var jsonResult = Assert.IsType<JsonResult>(result);
            Assert.NotNull(jsonResult.Value);

            var value = jsonResult.Value!;
            var successProp = value.GetType().GetProperty("success");
            Assert.NotNull(successProp);
            Assert.True((bool)successProp!.GetValue(value)!);
        }

        #endregion

        #region Index

        [Fact]
        public void Index_ReturnsViewResult()
        {
            var controller = CreateController();

            var result = controller.Index();

            Assert.IsType<ViewResult>(result);
        }

        #endregion
    }
}

